/** Roles that represent design-visible properties (always serialized). */
export const VISUAL_ROLES = new Set(['layout', 'fill', 'stroke', 'effect', 'appearance', 'typography']);


// ═══════════════════════════════════════════════════════════════
// Section 3: Property enrichment metadata (hand-maintained)
// Replaces PROP_METADATA from figma-api.ts — single source of truth
// for defaults, enum maps, constraints, and DSL aliases.
//
// Keyed by DSL name (what the LLM sees). figmaKey only needed when
// it differs from the DSL name (currently only gap → itemSpacing).
// ═══════════════════════════════════════════════════════════════

export interface SizingConstraint {
  readonly requiresAutoLayout: 'self' | 'parent';
  readonly fallback: string;
}

export interface PropMeta {
  readonly figmaKey?: string;   // Figma API name when ≠ DSL key (e.g. gap → itemSpacing)
  readonly type: 'scalar' | 'color' | 'enum' | 'object' | 'virtual' | 'array' | 'string';
  readonly enumMap?: Record<string, string>;
  readonly defaultValue?: any;
  readonly min?: number;
  readonly max?: number;
  readonly valueConstraints?: Record<string, SizingConstraint>;
}

